package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrint_WithValidPathAndCharset_ReturnsCSVPrinter() throws IOException {
        Path mockPath = mock(Path.class);
        Appendable mockAppendable = mock(Appendable.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Mock Files.newBufferedWriter to return a mock Appendable (Writer)
        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8))
                    .thenReturn(new StringWriter());

            // Spy on csvFormat to mock print(Appendable) method
            CSVFormat spyFormat = spy(csvFormat);
            doReturn(mockPrinter).when(spyFormat).print(any(Appendable.class));

            CSVPrinter result = spyFormat.print(mockPath, StandardCharsets.UTF_8);

            assertNotNull(result);
            assertEquals(mockPrinter, result);

            // Verify Files.newBufferedWriter was called with correct args
            filesMockedStatic.verify(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8));
            verify(spyFormat).print(any(Appendable.class));
        }
    }

    @Test
    void testPrint_ThrowsIOExceptionWhenFilesNewBufferedWriterFails() {
        Path mockPath = mock(Path.class);

        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8))
                    .thenThrow(new IOException("Test IO Exception"));

            IOException thrown = assertThrows(IOException.class, () -> {
                csvFormat.print(mockPath, StandardCharsets.UTF_8);
            });
            assertEquals("Test IO Exception", thrown.getMessage());

            filesMockedStatic.verify(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8));
        }
    }
}
